  ('locality-6e2f88c7-moex-00096', 'locality-6e2f88c7', 'locality-6e2f88c7-moex-113-9b7ab1bb', 'sub-locality-6e2f88c7-03', NULL, 'single_choice', '甲男及乙女分割丙父之遺產，甲分到一棟價值新臺幣（下同）500萬元之房子，乙分到丙對叔叔 丁之500萬元債權。乙分到此債權時，丁只付300萬元，即因破產再也無法返還乙200萬元。乙 就該丁未能償還之200萬元，得向甲請求多少金額？', '["50萬元", "100萬元", "200萬元", "乙不得向甲請求任何金額"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:47+00:00", "source_pdf_sha1": "86c11ebf16f6", "answer_pdf_sha1": "30cf5eb4aa24", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "315", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "法制"}'::jsonb, NULL),
